[{"proname":"add_credits","def":"CREATE OR REPLACE FUNCTION public.add_credits(p_user_id uuid, p_credits integer)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
BEGIN
  IF p_credits < 0 THEN
    RAISE EXCEPTION 'Credits amount must be non-negative, got %', p_credits;
  END IF;

  UPDATE profiles
  SET tokens = tokens + p_credits,
      updated_at = now()
  WHERE id = p_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'User not found: %', p_user_id;
  END IF;
END;
$function$
"},{"proname":"admin_adjust_credits","def":"CREATE OR REPLACE FUNCTION public.admin_adjust_credits(p_caller uuid, p_target uuid, p_mode text, p_amount integer, p_reason text DEFAULT NULL::text)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_old INTEGER;
  v_new INTEGER;
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  IF p_mode NOT IN ('set','delta') THEN
    RAISE EXCEPTION 'invalid_mode';
  END IF;
  SELECT tokens INTO v_old FROM public.profiles WHERE id = p_target FOR UPDATE;
  IF p_mode = 'set' THEN
    v_new := GREATEST(p_amount, 0);
  ELSE
    v_new := GREATEST(COALESCE(v_old,0) + p_amount, 0);
  END IF;
  UPDATE public.profiles SET tokens = v_new, updated_at = NOW() WHERE id = p_target;
  PERFORM public.admin_audit_insert(p_caller, 'credits.adjust', 'user', p_target::text,
    jsonb_build_object('tokens', v_old),
    jsonb_build_object('tokens', v_new, 'mode', p_mode, 'amount', p_amount, 'reason', p_reason));
  RETURN v_new;
END;
$function$
"},{"proname":"admin_audit_insert","def":"CREATE OR REPLACE FUNCTION public.admin_audit_insert(p_actor_id uuid, p_action text, p_target_type text DEFAULT NULL::text, p_target_id text DEFAULT NULL::text, p_before jsonb DEFAULT NULL::jsonb, p_after jsonb DEFAULT NULL::jsonb, p_metadata jsonb DEFAULT NULL::jsonb, p_ip text DEFAULT NULL::text, p_user_agent text DEFAULT NULL::text)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_id UUID;
  v_email TEXT;
BEGIN
  IF NOT public.is_admin(p_actor_id) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  SELECT email INTO v_email FROM public.profiles WHERE id = p_actor_id;
  INSERT INTO public.audit_log (actor_id, actor_email, action, target_type, target_id, before, after, metadata, ip_address, user_agent)
  VALUES (p_actor_id, v_email, p_action, p_target_type, p_target_id, p_before, p_after, p_metadata, p_ip, p_user_agent)
  RETURNING id INTO v_id;
  RETURN v_id;
END;
$function$
"},{"proname":"admin_audit_list","def":"CREATE OR REPLACE FUNCTION public.admin_audit_list(p_caller uuid, p_limit integer DEFAULT 200, p_offset integer DEFAULT 0, p_action_filter text DEFAULT NULL::text)
 RETURNS TABLE(id uuid, actor_id uuid, actor_email text, action text, target_type text, target_id text, before jsonb, after jsonb, metadata jsonb, ip_address text, user_agent text, created_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  RETURN QUERY
  SELECT a.id, a.actor_id, a.actor_email, a.action,
         a.target_type, a.target_id, a.before, a.after,
         a.metadata, a.ip_address, a.user_agent, a.created_at
  FROM public.audit_log a
  WHERE (p_action_filter IS NULL OR a.action = p_action_filter)
  ORDER BY a.created_at DESC
  LIMIT LEAST(p_limit, 1000) OFFSET GREATEST(p_offset, 0);
END;
$function$
