"},{"proname":"admin_list_tasks","def":"CREATE OR REPLACE FUNCTION public.admin_list_tasks(p_caller uuid, p_status text DEFAULT NULL::text, p_user_id uuid DEFAULT NULL::uuid, p_limit integer DEFAULT 100, p_offset integer DEFAULT 0)
 RETURNS TABLE(task_id text, user_id uuid, status text, topic text, tier text, budget_usd numeric, created_at timestamp with time zone, updated_at timestamp with time zone)
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  RETURN QUERY
  SELECT COALESCE(i.task_id, i.id::text)::text AS task_id,
         i.user_id,
         i.status::text,
         COALESCE(i.topic, i.ticker, i.hypothesis)::text AS topic,
         COALESCE(i.depth, 'standard')::text AS tier,
         COALESCE(i.budget_usd, 0)::numeric AS budget_usd,
         i.created_at,
         COALESCE(i.updated_at, i.created_at) AS updated_at
  FROM public.investigations i
  WHERE (p_status IS NULL OR i.status = p_status)
    AND (p_user_id IS NULL OR i.user_id = p_user_id)
  ORDER BY i.created_at DESC
  LIMIT LEAST(p_limit, 500) OFFSET GREATEST(p_offset, 0);
END;
$function$
"},{"proname":"admin_overview_stats","def":"CREATE OR REPLACE FUNCTION public.admin_overview_stats(p_caller uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v JSONB;
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  SELECT jsonb_build_object(
    'total_users', (SELECT COUNT(*) FROM public.profiles),
    'admins', (SELECT COUNT(*) FROM public.profiles WHERE role='admin'),
    'suspended', (SELECT COUNT(*) FROM public.profiles WHERE suspended_at IS NOT NULL),
    'active_24h', (SELECT COUNT(DISTINCT user_id) FROM public.investigations WHERE created_at >= NOW() - INTERVAL '24 hours'),
    'active_30d', (SELECT COUNT(DISTINCT user_id) FROM public.investigations WHERE created_at >= NOW() - INTERVAL '30 days'),
    'tasks_total', (SELECT COUNT(*) FROM public.investigations),
    'tasks_running', (SELECT COUNT(*) FROM public.investigations WHERE status IN ('PENDING','RUNNING')),
    'tasks_24h', (SELECT COUNT(*) FROM public.investigations WHERE created_at >= NOW() - INTERVAL '24 hours'),
    'tasks_failed_24h', (SELECT COUNT(*) FROM public.investigations WHERE created_at >= NOW() - INTERVAL '24 hours' AND status IN ('FAILED','HALTED')),
    'conversations', (SELECT COUNT(*) FROM public.conversations),
    'credits_spent_7d', (SELECT COALESCE(SUM(credits_spent),0) FROM public.usage_rollup_daily WHERE day >= CURRENT_DATE - INTERVAL '7 days'),
    'credits_spent_30d', (SELECT COALESCE(SUM(credits_spent),0) FROM public.usage_rollup_daily WHERE day >= CURRENT_DATE - INTERVAL '30 days'),
    'frozen', (SELECT frozen FROM public.system_status WHERE id=1)
  ) INTO v;
  RETURN v;
END;
$function$
"},{"proname":"admin_set_credits","def":"CREATE OR REPLACE FUNCTION public.admin_set_credits(target_user_id uuid, new_credits integer, is_delta boolean DEFAULT false)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  caller_role text;
  current_tokens integer;
  final_balance integer;
BEGIN
  SELECT role INTO caller_role FROM profiles WHERE id = auth.uid();
  IF caller_role IS DISTINCT FROM 'admin' THEN
    RAISE EXCEPTION 'Admin access required';
  END IF;

  IF is_delta THEN
    SELECT tokens INTO current_tokens FROM profiles WHERE id = target_user_id;
    IF current_tokens IS NULL THEN
      RAISE EXCEPTION 'User not found';
    END IF;
    final_balance := GREATEST(0, current_tokens + new_credits);
  ELSE
    final_balance := new_credits;
  END IF;

  UPDATE profiles SET tokens = final_balance, updated_at = now()
  WHERE id = target_user_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'User not found';
  END IF;

  RETURN final_balance;
END;
$function$
"},{"proname":"admin_set_role","def":"CREATE OR REPLACE FUNCTION public.admin_set_role(p_caller uuid, p_target uuid, p_new_role text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
DECLARE
  v_old TEXT;
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  IF p_new_role NOT IN ('user','admin','banned') THEN
    RAISE EXCEPTION 'invalid_role';
  END IF;
  SELECT role INTO v_old FROM public.profiles WHERE id = p_target;
  UPDATE public.profiles SET role = p_new_role, updated_at = NOW() WHERE id = p_target;
  PERFORM public.admin_audit_insert(p_caller, 'role.update', 'user', p_target::text,
    jsonb_build_object('role', v_old), jsonb_build_object('role', p_new_role));
END;
$function$
"},{"proname":"admin_suspend","def":"CREATE OR REPLACE FUNCTION public.admin_suspend(p_caller uuid, p_target uuid, p_suspend boolean, p_reason text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  IF p_suspend THEN
    UPDATE public.profiles
      SET suspended_at = NOW(), suspended_reason = p_reason, updated_at = NOW()
      WHERE id = p_target;
    PERFORM public.admin_audit_insert(p_caller, 'user.suspend', 'user', p_target::text,
      NULL, jsonb_build_object('reason', p_reason));
  ELSE
    UPDATE public.profiles
      SET suspended_at = NULL, suspended_reason = NULL, updated_at = NOW()
      WHERE id = p_target;
    PERFORM public.admin_audit_insert(p_caller, 'user.unsuspend', 'user', p_target::text,
      NULL, NULL);
  END IF;
END;
$function$
"},{"proname":"admin_system_freeze","def":"CREATE OR REPLACE FUNCTION public.admin_system_freeze(p_caller uuid, p_frozen boolean, p_reason text DEFAULT NULL::text, p_message text DEFAULT NULL::text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'auth'
AS $function$
BEGIN
  IF NOT public.is_admin(p_caller) THEN
    RAISE EXCEPTION 'not_admin';
  END IF;
  UPDATE public.system_status
    SET frozen = p_frozen,
        frozen_reason = p_reason,
        frozen_by = CASE WHEN p_frozen THEN p_caller ELSE NULL END,
        frozen_at = CASE WHEN p_frozen THEN NOW() ELSE NULL END,
        maintenance_message = p_message,
        updated_at = NOW()
    WHERE id = 1;
  PERFORM public.admin_audit_insert(p_caller,
    CASE WHEN p_frozen THEN 'system.freeze' ELSE 'system.unfreeze' END,
    'system','1', NULL,
    jsonb_build_object('frozen', p_frozen, 'reason', p_reason, 'message', p_message));
END;
$function$
"},{"proname":"deduct_credits","def":"CREATE OR REPLACE FUNCTION public.deduct_credits(target_user_id uuid, amount integer)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
AS $function$
DECLARE
  current_tokens integer;
  new_balance integer;
BEGIN
  -- Lock the row to prevent race conditions
  SELECT tokens INTO current_tokens
  FROM profiles
  WHERE id = target_user_id
  FOR UPDATE;

  IF current_tokens IS NULL THEN
    RAISE EXCEPTION 'User not found: %', target_user_id;
  END IF;

  IF amount < 0 THEN
    RAISE EXCEPTION 'Amount must be non-negative, got %', amount;
  END IF;

  -- BUG-016 fix: Reject deduction if user has insufficient tokens.
  -- Previously used GREATEST(0, ...) which silently allowed over-deduction.
  IF current_tokens < amount THEN
    RAISE EXCEPTION 'Insufficient credits: has %, needs %', current_tokens, amount
      USING ERRCODE = 'P0001';
  END IF;

  new_balance := current_tokens - amount;

  UPDATE profiles
  SET tokens = new_balance, updated_at = now()
  WHERE id = target_user_id;

  RETURN new_balance;
END;
$function$
"},{"proname":"expire_credits","def":"CREATE OR REPLACE FUNCTION public.expire_credits()
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_count integer := 0; v_b record; v_balance_after integer;
BEGIN
  FOR v_b IN SELECT id, user_id, remaining_credits FROM public.credit_buckets WHERE expires_at IS NOT NULL AND expires_at <= clock_timestamp() AND remaining_credits > 0 ORDER BY user_id, granted_at FOR UPDATE LOOP
    PERFORM pg_advisory_xact_lock(hashtextextended(v_b.user_id::text, 0));
    UPDATE public.credit_buckets SET remaining_credits = 0 WHERE id = v_b.id;
    SELECT COALESCE(SUM(remaining_credits),0) INTO v_balance_after FROM public.credit_buckets WHERE user_id = v_b.user_id;
    INSERT INTO public.credit_transactions (user_id, type, credits, bucket_id, ref_type, ref_id, balance_after, metadata)
      VALUES (v_b.user_id, 'expiry', v_b.remaining_credits, v_b.id, 'bucket', v_b.id::text, v_balance_after, jsonb_build_object('source','expiry'));
    v_count := v_count + 1;
  END LOOP;
  RETURN v_count;
END;$function$
"},{"proname":"get_my_balance","def":"CREATE OR REPLACE FUNCTION public.get_my_balance()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'pg_temp'
AS $function$
DECLARE v_user uuid := auth.uid(); v_balance integer; v_next_expiry timestamptz;
BEGIN
  IF v_user IS NULL THEN RAISE EXCEPTION 'get_my_balance: not authenticated'; END IF;
  SELECT COALESCE(SUM(remaining_credits),0)::integer, MIN(expires_at) FILTER (WHERE remaining_credits>0 AND expires_at IS NOT NULL) INTO v_balance, v_next_expiry FROM public.credit_buckets WHERE user_id = v_user AND remaining_credits > 0;
  RETURN jsonb_build_object('balance', v_balance, 'next_expiry', v_next_expiry);
END;$function$
"},{"proname":"get_stripe_customer_id","def":"CREATE OR REPLACE FUNCTION public.get_stripe_customer_id(target_user_id uuid)
